(14, 'terms_condition', '<p><strong>1. Acceptance of Terms</strong></p>\r\n\r\n<p>By using paperproc.com and its website, you agree to comply with and be bound by the following terms and conditions. If you do not agree to these terms, please refrain from using our services.</p>\r\n\r\n<p><strong>2. User Accounts</strong></p>\r\n\r\n<ul>\r\n	<li>You must create an account to use certain features of our website.</li>\r\n	<li>You are responsible for maintaining the security of your account credentials.</li>\r\n	<li>You agree to provide accurate and up-to-date information during registration.</li>\r\n	<li>You are solely responsible for all activities conducted through your account.</li>\r\n</ul>\r\n\r\n<p><strong>3. Buying and Selling Books</strong></p>\r\n\r\n<ul>\r\n	<li>Users may list books for sale and purchase books from other users through our platform.</li>\r\n	<li>We do not own or inspect the books listed, and we do not guarantee the quality, condition, or accuracy of book listings.</li>\r\n	<li>Users are responsible for accurate book descriptions, pricing, and fulfillment of orders.</li>\r\n	<li>Buyers and sellers are responsible for any disputes arising from transactions.</li>\r\n</ul>\r\n\r\n<p><strong>4. Payment</strong></p>\r\n\r\n<ul>\r\n	<li>Payments for books and related services are processed through our secure payment system.</li>\r\n	<li>Sellers may be subject to transaction fees as specified in our pricing terms.</li>\r\n	<li>Payments are subject to our refund and dispute resolution policies.</li>\r\n</ul>\r\n\r\n<p><strong>5. Intellectual Property</strong></p>\r\n\r\n<ul>\r\n	<li>Users retain ownership of their intellectual property rights in book listings.</li>\r\n	<li>By using our platform, users grant us a non-exclusive license to use, display, and promote their listings.</li>\r\n	<li>Users may not use our platform to infringe on the intellectual property rights of others.</li>\r\n</ul>\r\n\r\n<p><strong>6. Prohibited Activities</strong></p>\r\n\r\n<ul>\r\n	<li>Users may not engage in illegal, fraudulent, or harmful activities on our website.</li>\r\n	<li>Users may not use our platform for spamming, phishing, or distributing malware.</li>\r\n	<li>We reserve the right to terminate or suspend accounts that violate these terms.</li>\r\n</ul>\r\n\r\n<p><strong>7. Content and User Conduct</strong></p>\r\n\r\n<ul>\r\n	<li>Users are responsible for the content they post on our platform.</li>\r\n	<li>We do not endorse or guarantee the accuracy of user-generated content.</li>\r\n	<li>We may remove or modify content that violates these terms.</li>\r\n</ul>\r\n\r\n<p><strong>8. Privacy</strong></p>\r\n\r\n<ul>\r\n	<li>Our use of your personal information is governed by our Privacy Policy.</li>\r\n	<li>By using our platform, you consent to the collection and use of your data as outlined in the Privacy Policy.</li>\r\n</ul>\r\n\r\n<p><strong>9. Termination</strong></p>\r\n\r\n<ul>\r\n	<li>We reserve the right to suspend or terminate user accounts for any reason, including violations of these terms.</li>\r\n	<li>Users can terminate their accounts by contacting us.</li>\r\n</ul>\r\n\r\n<p><strong>10. Disclaimers and Limitation of Liability</strong></p>\r\n\r\n<ul>\r\n	<li>We provide our platform &quot;as is&quot; and do not guarantee its availability or functionality.</li>\r\n	<li>We are not responsible for the actions or inactions of users on our platform.</li>\r\n	<li>Our liability is limited to the maximum extent permitted by law.</li>\r\n</ul>\r\n\r\n<p><strong>11. Changes to Terms</strong></p>\r\n\r\n<ul>\r\n	<li>We may update these terms from time to time, and any changes will be posted on our website.</li>\r\n	<li>Continued use of our platform after changes constitute acceptance of the updated terms.</li>\r\n</ul>', NULL, '2023-09-27 05:53:48'),
(15, 'about_us', '<p><strong>About us</strong></p>\r\n\r\n<p>Welcome to Paper Processing and Packaging Ltd. (PPP), your trusted partner in the world of knowledge and inspiration. At PPP, we are more than just a publication company; we are dedicated to enhancing lives through the power of books. Our e-commerce platform, PaperProc, is where you&#39;ll discover a treasure trove of mathematics, religion, skill development, and many more books to enlighten your mind and enrich your soul.</p>\r\n\r\n<p><strong>Our Mission</strong></p>\r\n\r\n<p>At Paperproc, our mission is to empower readers and book enthusiasts by providing a seamless, user-friendly platform to buy and sell books. We believe in the magic of books to inspire, educate, and entertain, and we&#39;re committed to fostering a vibrant community of bibliophiles.</p>', NULL, '2023-09-27 06:05:19'),
