INSERT INTO `help_topics` (`id`, `question`, `answer`, `ranking`, `status`, `created_at`, `updated_at`) VALUES
(1, 'How do I buy a book on Paperproc?', 'To purchase a book on our platform, follow these steps:\r\n•	Log in to your account or create one if you haven\'t already.\r\n•	Search for the book you want using our search bar or browse our categories.\r\n•	Click on the book listing to view more details.\r\n•	Click the \"Add to Cart\" or \"Buy Now\" button.\r\n•	Follow the prompts to complete your purchase, including providing shipping and payment information.', 1, 1, '2023-09-27 05:57:19', '2023-09-27 05:57:19'),
(2, 'How can I sell my books on Paperproc?', 'Selling books on our platform is easy:\r\n•	Log in to your account or create one if you haven\'t already.\r\n•	Click on the \"Sell\" option.\r\n•	Fill in the details about the book you want to sell, including title, author, condition, and price.\r\n•	Upload clear images of the book.\r\n•	Click \"Submit Listing\" to make your book available for sale.', 2, 1, '2023-09-27 05:59:25', '2023-09-27 06:00:55'),
(3, 'What payment methods are accepted?', 'We accept a variety of payment methods, including COD and mobile banking. Payment options may vary based on your location and may be subject to change. During the checkout process, you will see the available payment methods for your order.', 1, 1, '2023-09-27 06:00:39', '2023-09-27 06:00:39'),
(4, 'Can I return a book if I\'m not satisfied?', 'Our return policy may vary depending on the individual seller\'s terms. Please review the seller\'s return policy before making a purchase. If you encounter any issues with your order, please contact the seller directly for resolution.', 1, 1, '2023-09-27 06:01:35', '2023-09-27 06:01:35'),
(5, 'Is my personal information secure?', 'We take your privacy seriously. We employ industry-standard security measures to protect your personal information. For more details on how we handle your data, please review our Privacy Policy.', 1, 1, '2023-09-27 06:02:00', '2023-09-27 06:02:00'),
(6, 'How do I contact customer support?', 'If you have any questions, issues, or need assistance, you can reach our customer support team by using messenger or whatsapp chat option. We\'re here to help and respond as promptly as possible.', 1, 1, '2023-09-27 06:02:22', '2023-09-27 06:02:22'),
(7, 'Are there fees for selling books on your platform?', 'We charge fees for listing and selling books on our platform. The exact fees may vary, so please review our Pricing and Fees page for detailed information.', 1, 1, '2023-09-27 06:02:44', '2023-09-27 06:02:44'),
(8, 'How can I track my order once it\'s been shipped?', 'You will receive a shipping confirmation email with tracking information once your order has been shipped. You can use this information to track your package on the carrier\'s website.', 1, 1, '2023-09-27 06:03:17', '2023-09-27 06:03:17'),
(9, 'Do you offer international shipping?', 'Shipping options and availability may vary based on your location and the seller\'s preferences. During the checkout process, you will see the available shipping options for your order.', 1, 1, '2023-09-27 06:03:41', '2023-09-27 06:03:41'),
(10, 'How do I change my account information, such as my email address or password?', 'You can update your account information by logging in to your account and navigating to the \"Account Settings\" or \"Profile\" section. From there, you can make the necessary changes.', 1, 1, '2023-09-27 06:03:58', '2023-09-27 06:03:58');
