INSERT INTO `translations` (`translationable_type`, `translationable_id`, `locale`, `key`, `value`, `id`) VALUES
('App\\Model\\Product', 2, 'bd', 'name', 'Bioaqua Pure Skin Acne Removal and Rejuvenation Cream -25 gm', 1),
('App\\Model\\Product', 2, 'bd', 'description', '<h2>Bioaqua Pure Skin Acne Removal and Rejuvenation Cream -25 gm</h2>\r\n\r\n<ul>\r\n	<li>Acne spot treatment.</li>\r\n	<li>Acne scar removal.</li>\r\n	<li>Pimple.</li>\r\n	<li>Blemish gel.</li>\r\n	<li>Face cleaning.</li>\r\n	<li>Gentle Skin Moisturizing.</li>\r\n	<li>Help to Gain Clean &amp; Smooth Skin.</li>\r\n</ul>\r\n\r\n<p>Gentle moisturizing the skin, the to add plenty of moisture and nutrients balance water and oil, to help to remove acne, pimples and gives skin smoothness delicate to tender and moist. Repair Uneven Rough Skin, Making Skin Smooth And Delicate Shrink Pores, Improve Skin Elasticity And Balanced Facial Oil Secretion It Get Rid Of Acne Scars, Acne Marks And Repairing Damage To The Skin. Help to Gain Clean and Smooth Skin and useful to all skin type.The seller, offers a wide selection of products from renowned brands in Bangladesh with a promise of fast, safe and easy online shopping experience through Daraz. The seller comes closer to the huge customers on this leading online shopping platform of all over Bangladesh and serving to the greater extent for achieving higher customer satisfaction. The brands working with Daraz are not only serving top class products but also are dedicated to acquiring brand loyalty.</p>', 2),
('App\\Model\\Product', 36, 'bd', 'name', 'Ar Vitamin E Moisturizing Cream for Face', 3),
('App\\Model\\Product', 36, 'bd', 'description', '<p>This product comes with very attractive design. The material used in it will meet your expectation and need also. Now with a new look it is even better than before and its quality will definitely meet your desire. So you may take this to bring smile and enjoy the feel of good quality product.</p>', 4),
('App\\Model\\Product', 93, 'bd', 'name', 'Neutrogena Oil Free Facial Moisturizer, SPF 15, 115ml', 5),
('App\\Model\\Product', 93, 'bd', 'description', '<p>Proven to combine long-lasting 12 hour miniaturization with sun protection for softer, smoother, younger-looking skin. Lightweight, non-greasy lotion keeps skin moisturized and sheer formula absorbs quickly into skin leaving it softer and smoother. It doesn&#39;t clog pores and is dermatologist tested.</p>', 6),
('App\\Model\\Product', 219, 'bd', 'name', '1/3 Beaute White Serum Hi Speed X10 Brighter Skin Reduce Dark Spts (30Ml)', 7),
('App\\Model\\Product', 219, 'bd', 'description', '<h2>Highlights</h2>\r\n\r\n<ul>\r\n	<li>Serum Natcha Hi Speed x10</li>\r\n	<li>Selected natural extracts for urgent skin care Enriched with 10 natural extracts and concentrated arbutin For maximum efficiency Ready to return youthfulness to beautiful skin. Naturally ❌❌ 100% free from harmful chemicals</li>\r\n</ul>\r\n\r\n<h2>Description</h2>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Blemish melting serum, face recovery, brighter skin 10 times, skin rejuvenation urgently, reduce dark spots caused by acne and melasma.</p>\r\n\r\n<p>4 Natural Extracts</p>\r\n\r\n<p>1. Licorice helps to clear toxins that remain on the skin, reduce fade, freckles, dark spots.</p>\r\n\r\n<p>2. Phuttha slows down wrinkles of age, strengthens the skin.</p>\r\n\r\n<p>3. Scaly, helps the skin glow.</p>\r\n\r\n<p>4. Alpha Arbutin inhibits melanin pigment, prevents dull skin</p>', 8),
('App\\Model\\Product', 68, 'bd', 'name', 'KOJIC COLLAGEN BODY LOTION', 9),
('App\\Model\\Product', 68, 'bd', 'description', '<h2>Highlights</h2>\r\n\r\n<ul>\r\n	<li>★মুখ ও পুরো শরীর ফর্সা করে স্থায়ী ভাবে।</li>\r\n	<li>★ব্রণ ও কালো দাগ দূর করবে,</li>\r\n	<li>★বয়সের ছাপ মুছে দিবে</li>\r\n	<li>★কুচকে যাওয়া ত্বককে টানটান করবে</li>\r\n	<li>★চোখের নিচে কালো দাগ দূর করে</li>\r\n	<li>★স্কিনকে নরম ও কমল করে তুলবে</li>\r\n	<li>★স্কীনের তৈলাক্ত ভাব দূর করে</li>\r\n	<li>★ত্বকের ডার্কসার্কেল দূর করবে</li>\r\n	<li>★স্কিনের মৃত্য কোষ দূর করবে</li>\r\n	<li>★স্কিনের হোয়াইটহেডস দূর্র করবে</li>\r\n	<li>★আপনি ভিতর থেকে স্থায়ীভাবে ফর্সা হবেন।</li>\r\n	<li>★সমস্ত শরীর ফর্সা করবে৷</li>\r\n	<li>★আপনার মুখে ব্রন থাকলে চলে যাবে যে কোন দাগ বা ঘা ফাসড়া</li>\r\n	<li>থাকলেও চলে যাবে। কারন এখানে নিম এবং হলুদ আছে।</li>\r\n	<li>★রক্ত পরিষ্কার করবে৷</li>\r\n	<li>★স্কিনকে স্মুথ এবং গ্লো করে</li>\r\n</ul>', 10),
('App\\Model\\Product', 69, 'bd', 'name', 'BIOAQUA Skin Lightening Whitening Face Body Cream Pink Lips Armpit Private Part', 11),
('App\\Model\\Product', 69, 'bd', 'description', '<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Scent</td>\r\n			<td>Cherry</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Item form</td>\r\n			<td>Cream</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Product benefits</td>\r\n			<td>Hydrating,Whitening</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Use for</td>\r\n			<td>Face</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Brand</td>\r\n			<td>Bioaqua</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<hr />\r\n<h1><strong>About this item</strong></h1>\r\n\r\n<ul>\r\n	<li>Gentle on the skin, give the skin attentive care.</li>\r\n	<li>Supplements the skin with essential moisture giving it softness and hydration.</li>\r\n	<li>Improves skin tone and moisturizes it. Natural beauty skin care flower.</li>\r\n	<li>Flowers of cherries are rich in peptides and vitamins. They gently nourish the skin, giving it a matte glow.</li>\r\n	<li>Make yourself more beautiful. Give your body the charming color.</li>\r\n</ul>\r\n\r\n<h1><strong>Product description</strong></h1>\r\n\r\n<p>Delicate pink temptation: 1. Gentle on the skin, give the skin attentive care. 2. Supplements the skin with essential moisture giving it softness and hydration. 3. Improves skin tone and moisturizes it. Cherry blossom is a natural beauty skin care flower. Flowers of cherries are rich in peptides and vitamins. They gently nourish the skin, giving it a matte glow. Make yourself more beautiful. Give your body the charming color. Pink seductive. Rosy charm. Pink temptation. Method of use: A matte finish lip color. Apply on the lips evenly, making lips pink and wet. Pink nipple areola. Gently massage into the skin until fully absorbed. Pink skin. Apply on the inner part of the thigh, allows to wear a bikini more confidently.</p>', 12),
('App\\Model\\Product', 37, 'bd', 'name', 'Simple Kind To Skin Hydrating Light Moisturiser', 13),
('App\\Model\\Product', 37, 'bd', 'description', '<p>Keep your skin hydrated all day long with Simple&nbsp;Hydrating Light Moisturizer. This light, silky formula provides up to&nbsp;12 hours of hydration&nbsp;and instantly doubles skin&#39;s hydration. It is made with added vitamins and a blend of skin-loving ingredients. This moisturizer contains no dyes, artificial perfumes, or harsh chemicals that can upset skin so it won&#39;t clog pores or feel greasy&nbsp;</p>', 14),
('App\\Model\\Product', 38, 'bd', 'name', 'The Body Shop Vitamin C Glow Boosting Moisturiser', 15),
('App\\Model\\Product', 38, 'bd', 'description', '<p>The Vitamin C Glow Boosting Moisturiser is a fresh, lightweight gel formula that will give your skin a daily boost of radiance and hydration. Vitamin C moisturiser is infused with camu camu berries, it awakens and clarifies your complexion, revealing a natural healthy-looking glow. It&rsquo;s also enriched with Community Fair Trade aloe vera in a gel formula, helping to refresh your complexion. Just smooth it on and soak up the aloe vera and vitamin C benefits for skin.</p>\r\n\r\n<p>&nbsp;</p>', 16),
('App\\Model\\Product', 51, 'bd', 'name', 'Neutrogena Pink Grapefruit Oil Free Moisturiser 50ml', 17),
('App\\Model\\Product', 51, 'bd', 'description', '<p>Formulated for blemish-prone skin, NEUTROGENA&reg; Refreshingly Clear Oil-Free Moisturiser gives 24-hour hydration without clogging pores. Developed with dermatologists, the refreshing, light formula has a pink grapefruit fragrance and helps to keep skin clear and radiant.</p>', 18),
('App\\Model\\Product', 70, 'bd', 'name', 'Snail White Body Lotion', 21),
('App\\Model\\Product', 70, 'bd', 'description', '<h2>Highlights</h2>\r\n\r\n<ul>\r\n	<li>Snail White Body Lotion</li>\r\n	<li>Type: Body Lotion</li>\r\n	<li>Size: 350ml</li>\r\n	<li>Hydrates and protects.</li>\r\n	<li>Easily absorbed.</li>\r\n	<li>Leaves skin feeling soft and smooth.</li>\r\n	<li>All skin types.</li>\r\n</ul>', 22),
('App\\Model\\Product', 43, 'bd', 'name', 'Pure Natural Nutrients AICHUN BEAUTY Beard Oil - 30ml', 23),
('App\\Model\\Product', 43, 'bd', 'description', '<p>Product Description</p>\r\n\r\n<p>New cheap aichun beard growth liquid beard growth oil,beard enhancer,men products,beard liquid from men 30ml.</p>\r\n\r\n<p>Aichun Beauty Beard Growth Essential Oil Enhance Facial Whiskers Nutrition Moustache</p>\r\n\r\n<p><br />\r\n<em><strong>Feature:</strong></em></p>\r\n\r\n<p>This oil is enriched with multiple natural nourishing ingredients that infiltrate into the hair follicle roots,&nbsp;repair &amp; activate the dormant hair follicles, increase nutrient absorption and accelerate hairgrowth.</p>\r\n\r\n<p><br />\r\nApplicability: Beards, armpit hair, chest hair, pubic hair and the areas required for hair growth.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><em><strong>Ingredients:</strong></em></p>\r\n\r\n<p>Zingiber Officinale Root Oik,Juniperus Virginiana Oil,Rosmarinus Officinalis Leaf Oil,vitam- in E,<br />\r\nCitrus Paradisi Seed Oil.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><em><strong>Usage:</strong></em></p>\r\n\r\n<p>After bath every day, apply proper amount evenly and fully massage until absorption.</p>', 24),
('App\\Model\\Product', 45, 'bd', 'name', 'POWER KNIGHT PRO FIBER HAIR MASK', 25),
('App\\Model\\Product', 45, 'bd', 'description', '<h2>POWER KNIGHT PRO FIBER HAIR MASK</h2>\r\n\r\n<ul>\r\n	<li>This super smoothing Detangeling hair treatment is one of our most effective hair treatments.</li>\r\n	<li>It is designed to successfully treat damaged hair and aid the recovery from any previous chemical treatments.</li>\r\n	<li>Our unique formula promotes healthy and strong hair, reducing split ends and breakage and giving instant results of revitalized, smooth and manageable hair.</li>\r\n	<li>Results may vary depending on the application and texture of hair.</li>\r\n</ul>', 26),
('App\\Model\\Product', 66, 'bd', 'name', 'Scru Cream For pink lips', 27),
('App\\Model\\Product', 66, 'bd', 'description', '<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Brand</td>\r\n			<td>Balai</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Product benefits</td>\r\n			<td>Moisturizing,Exfoliating</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Active ingredients</td>\r\n			<td>Vitamin e,sodium hyaluronate</td>\r\n		</tr>\r\n	</tbody>\r\n</table>\r\n\r\n<hr />\r\n<h1>About this item</h1>\r\n\r\n<ul>\r\n	<li>★If your chapped lips are keeping you from showing your smile, our propolis lip scrub is here to change that.</li>\r\n	<li>★This scrub is a safe, gentle, and effective way to banish dry, flaky lips. Use it to exfoliate twice a week for a smile you&rsquo;ll have a hard time hiding.</li>\r\n	<li>★You don&#39;t need to apply lip balm every hour to keep your lips healthy. Our exfoliator works wonders to clear away dead skin and other junk while nourishing your lips with some of our favorite oils and extracts.</li>\r\n	<li>★When you&rsquo;re done, your lips will exude health, happiness, and radiance - and they will feel as healthy as they look.</li>\r\n	<li>★Package Contents:1 Pcs Professional Moisturizing Lip Cream Crystal Clear &amp; Hydrated Skin with Water Science Remove Dead Skin Exfoliating Lip Scrub Care</li>\r\n</ul>\r\n\r\n<h1><strong>Product description</strong></h1>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p>Balai Propolis Lip Exfoliating Gel Moisturizing Anti-Drying Firming Skin Lips Care Product</p>\r\n\r\n<h1><strong>Description:</strong></h1>\r\n\r\n<p>1.This product has super moisturizing effect. The product is rich in sodium hyaluronate, which can deeply penetrate the skin and tightly lock the moisture of the skin.</p>\r\n\r\n<p>2.This product has a good nourishing effect. The product is rich in collagen, which can provide enough collagen for the lips and deeply nourish the skin.</p>\r\n\r\n<p>3.The product is rich in vitamin E collagen, which can promote the growth of lip muscles, remove the aging skin tissue, make the skin of the lips more full and more elastic.</p>\r\n\r\n<p>4.The rose extract in the product has a good whitening nourishing function, which can make the lips more red and shiny.</p>\r\n\r\n<p>5.This product is lightweight and easy to carry, so you can moisturize your lips at any time.</p>\r\n\r\n<p>Specifications:</p>\r\n\r\n<p>Type:Lip care product</p>\r\n\r\n<p>Gender:Unisex</p>\r\n\r\n<p>Color:Clear</p>\r\n\r\n<p>Shelf life:3 years</p>\r\n\r\n<p>Feature:Moisturizing, Anti-Drying, Exfoliating</p>\r\n\r\n<p>NET WT:12g</p>\r\n\r\n<p>Package Size:10*3*3cm/3.94*1.18*1.18&quot;</p>\r\n\r\n<p>Package included:</p>\r\n\r\n<p>1 x Propolis Lip Exfoliating Gel</p>', 28),
('App\\Model\\Product', 73, 'bd', 'name', 'Yogurt Milk Underarm Cream', 29),
('App\\Model\\Product', 73, 'bd', 'description', '<h2>Highlights</h2>\r\n\r\n<ul>\r\n	<li>[Function] : 7 in 1 benefits - Reduce Odor, Smoothen Skin,</li>\r\n	<li>Non Irritate Skin, Natural Deodorant, Whiten Underarm, Reduce Dark Spots, Minimizes Pores.</li>\r\n	<li>After shower, towel dry and apply A Bonne Whitening Underarm Cream onto the underarm area.</li>\r\n	<li>[Main Ingredients] : Milk Protein, Aloe Vera, Vitamin B3, Glutathione, Wasabi, Willow Beak Extract.</li>\r\n	<li>[Registration No.] : 10-1-6009119, Product of Thailand.</li>\r\n	<li>[100% Satisfaction Guarantee] - 100% MONEY GUARANTEE.</li>\r\n	<li>7 in 1- fade melanin, wrinkles, remove the smell, anti-inflammatory, repair, whitening, replenishment</li>\r\n	<li>Enriched with multiple natural fruit extracts that help lighten dull armpits, firm,repair rough pores after hair removal</li>\r\n	<li>Moisturize and soothe the underarm skin, making it look fair, smooth, soft and bright</li>\r\n	<li>It also helps remove underarm odor and keeps the skin fresh and soothe</li>\r\n	<li>It has mild properties and causes no irritaion.</li>\r\n</ul>', 30),
('App\\Model\\Product', 96, 'bd', 'name', 'Aveeno Active Naturals Daily Moisturizing Lotion (200gm)', 31),
('App\\Model\\Product', 96, 'bd', 'description', '<p>The unique formula of Aveeno Daily Moisturising Lotion is clinically proven to go beyond 24 hour moisturisation and replenish the skin&rsquo;s natural barrier function, to significantly improve the condition of dry skin in just 2 weeks.</p>\r\n\r\n<ul>\r\n	<li>Absorbs quickly and leaves skin looking and feeling soft, smooth and healthy.</li>\r\n	<li>Fragrance and paraben free.</li>\r\n	<li><strong>Significantly improves the condition of dry skin in just 2 weeks</strong></li>\r\n	<li>Moisturises skin for 24 hours</li>\r\n	<li>Available in two sizes: 200ml and 300ml</li>\r\n	<li>For best results, apply daily after your bath or shower.</li>\r\n</ul>', 32),
('App\\Model\\Product', 145, 'bd', 'name', 'WOW Red Onion Skin Mist Toner - 200 ml', 33),
('App\\Model\\Product', 145, 'bd', 'description', '<h2>Product details of WOW Red Onion Skin Mist Toner - 200 ml</h2>\r\n\r\n<ul>\r\n	<li>Rejuvenate your tired, aging skin with WOW Skin Science Red Onion Black Seed Oil Skin Mist Toner. It is a hydrating, reviving and repairing facial mist to help you get dewy youthful skin. This spray offers you the dual benefit of toner and mist. It aids in minimizing pores and firming up skin and also delivers instant moisture to dehydrated skin.The formulation is loaded with skin-loving natural actives like skin repairing red onion seed extract and black seed oil. Witch hazel in the water helps to tone and soothe your skin. Aloe vera hydrates the skin and restores its natural moisture mantle.This facial mist toner can be used to wipe away excess sebum and residual dirt from your skin. It also hydrates dry, dehydrated skin and smoothens fine lines. The mist helps to calm and balance skin while refreshing dull, tired skin. It makes skin supple and reduces visible signs of aging. When you need an instant pick-me-up for dull, tired skin, reach for this mist toner. Simply spray it on your skin and see it revived.WHY YOU WOULD LOVE THIS MIST TONERHelps to repair and revive aging skin.Helps to hydrate skin and keep it soft.Helps to refresh and revive dull skin.Safe and skin friendly always.KEY INGREDIENTSPurified Water, Glycerin (Vegetable Derived), Propanediol, Witch Hazel Extract, Aloe Vera Extract, Red Onion Seed Extract, Black Seed Oil, Polysorbate 20, Phenoxyethanol, Benzyl Alcohol, Fragrance &amp; Sodium Gluconate.HOW TO USECleanse your face thoroughly. Hold the bottle a few inches away from your face and spray the mist on your skin. Let the mist settle on the skin. Then gently dab your face with your palm. Your skin becomes dewy soft, and fresh. You can use it over your makeup, and when your skin feels drawn and tight mid-day to rehydrate. Use this with a cotton pad to wipe away grime and excess oil.</li>\r\n</ul>', 34),
('App\\Model\\Product', 156, 'bd', 'name', 'Boots Cucumber Facial Toner', 35),
('App\\Model\\Product', 156, 'bd', 'description', '<h2>Product details of Boots Cucumber Facial Toner</h2>\r\n\r\n<ul>\r\n	<li>Enriched with cucumber and vitamins.</li>\r\n	<li>Removes excess oils also.</li>\r\n	<li>Makes the skin soft.</li>\r\n</ul>\r\n\r\n<p>We&#39;ve lovingly formulated our skin care range enriched with cooling cucumber and vitamins to gently care for your skin.Our toner will cleanse your skin by sweeping away the last traces of make-up as well as those unwanted excess oils and impurities after cleansing. Your skin will be left feeling thoroughly refreshed, toned and beautifully soft.</p>\r\n\r\n<p>How to use</p>\r\n\r\n<p>Pop some on a cotton wool pad and sweep over your skin before moisturising.</p>\r\n\r\n<h2>Specifications of Boots Cucumber Facial Toner</h2>\r\n\r\n<ul>\r\n	<li>Brand\r\n	<p>Boots</p>\r\n	</li>\r\n	<li>SKU\r\n	<p>132166854_BD-1052954293</p>\r\n	</li>\r\n	<li>Volume\r\n	<p>20 ml</p>\r\n	</li>\r\n	<li>Capacity\r\n	<p>150ml</p>\r\n	</li>\r\n	<li>Pack Size\r\n	<p>1</p>\r\n	</li>\r\n	<li>Country of Origin\r\n	<p>Not Specified</p>\r\n	</li>\r\n</ul>', 36),
