('App\\Model\\Product', 65, 'bd', 'description', '<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>SYSTEM REQUIREMENTS</td>\r\n			<td>Operating System: Windows 7 with Service Pack 1, Windows 8, Windows 8.1, and Windows 10<br />\r\n			Memory (RAM): 2 GB<br />\r\n			Available free hard disk space: 2.5 GB free space<br />\r\n			*System performance may be affected on devices that have old generation CPUs</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Performance:</td>\r\n			<td>Autopilot<br />\r\n			Bitdefender Photon&trade;<br />\r\n			Global Protective Network<br />\r\n			Game, Movie &amp; Work Profiles<br />\r\n			Battery Mode</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Privacy</td>\r\n			<td>Bitdefender VPN IMPROVED<br />\r\n			Anti-tracker<br />\r\n			Microphone Monitor<br />\r\n			Webcam Protection<br />\r\n			Safe Online Banking<br />\r\n			Parental Control<br />\r\n			Privacy Firewall<br />\r\n			Wi-Fi Security Advisor<br />\r\n			Social Network Protection<br />\r\n			Password Manager<br />\r\n			File Shredder</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Protection:</td>\r\n			<td>Complete Real-Time Data Protection IMPROVED<br />\r\n			Network Threat Prevention<br />\r\n			Advanced Threat Defense<br />\r\n			Multi-Layer Ransomware Protection<br />\r\n			Vulnerability Assessment IMPROVED<br />\r\n			Web Attack Prevention<br />\r\n			Anti-Phishing<br />\r\n			Anti-Fraud<br />\r\n			Antispam<br />\r\n			Rescue Environment</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 112),
