('App\\Model\\Product', 48, 'bd', 'description', '<table>\r\n	<tbody>\r\n		<tr>\r\n			<td>Warranty</td>\r\n			<td>01 Year Battery &amp; Service with Spare Parts</td>\r\n		</tr>\r\n	</tbody>\r\n	<tbody>\r\n		<tr>\r\n			<td>Input</td>\r\n			<td>Voltage Range: 145-280VAC<br />\r\n			Frequency: 50/60Hz+/-5%</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Battery</td>\r\n			<td>Type: Lead-Acid Maintenance-Free<br />\r\n			DC Bus: 12V 7.2Ah<br />\r\n			Number: 1 PCS<br />\r\n			Recharge time: 6 hours up to 90% capacity<br />\r\n			Back up time: 05-15 mins (Depending on load)</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Protection</td>\r\n			<td>Spike &amp; Surge Suppression: Yes<br />\r\n			Over/Under Volt.: Switch to Bat. O / P when main over-regulation range<br />\r\n			Overload /short Circuit: Fuse &amp; current limited for both Mains and Battery modes</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Function</td>\r\n			<td>Cool start: Cool start computer even there is no main power<br />\r\n			Automatic recharge: Automatic recharge even UPS is off</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Output</td>\r\n			<td>Voltage (Inverter Mode): 220/230VAC+/-10%<br />\r\n			Capacity: 390W<br />\r\n			Frequency (Inverter Mode): 50/60Hz+/-5%<br />\r\n			Transfer Time: 2~6ms typical<br />\r\n			Waveform: Modified-Sinewave</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Basic Information</td>\r\n			<td>Model: PG 650 VA &ndash; C S Capacity: 650 VA / 390W</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Indicators</td>\r\n			<td>AC Mode: Green lighting<br />\r\n			Battery Mode: Red lighting<br />\r\n			Over Load: Yellow lighting</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Alarm</td>\r\n			<td>Beeping Alarm</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Environmental</td>\r\n			<td>Temperature: -5-45&deg; C<br />\r\n			Humidity: 20% to 90%</td>\r\n		</tr>\r\n		<tr>\r\n			<td>Management</td>\r\n			<td>Intelligent Battery Management</td>\r\n		</tr>\r\n	</tbody>\r\n</table>', 118),
